const csv = $input.first().json.data;
const lines = csv.split('\n').filter(l => l.trim());
const rows = lines.slice(1).map(line => {
  const vals = [];
  let inQuote = false, cur = '';
  for (const ch of line) {
    if (ch === '"') { inQuote = !inQuote; }
    else if (ch === ',' && !inQuote) { vals.push(cur.trim()); cur = ''; }
    else { cur += ch; }
  }
  vals.push(cur.trim());
  return vals;
});
const DONE = ['drafted','published','done','processing'];
for (let i = 0; i < rows.length; i++) {
  const row = rows[i];
  const sourceUrl = row[0] || '';
  const topic = row[1] || '';
  const keywords = row[2] || '';
  const statusC = (row[2] || '').toLowerCase().trim();
  const statusD = (row[3] || '').toLowerCase().trim();
  const statusE = (row[4] || '').toLowerCase().trim();
  if (!sourceUrl || !sourceUrl.startsWith('http')) continue;
  if (DONE.some(d => [statusC, statusD, statusE].includes(d))) continue;
  return [{
    json: {
      rowIndex: i + 2,
      sourceUrl: sourceUrl,
      topic: topic || 'wellness research',
      keywords: keywords
    }
  }];
}
return [{ json: { rowIndex: -1, message: 'No pending source rows' } }];

const html = $input.first().json.data || '';
const text = html.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '').replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/\s+/g, ' ').trim().substring(0, 3000);
const sourceUrl = $('Find Next Source Row').first().json.sourceUrl;
const topic = $('Find Next Source Row').first().json.topic;
const keywords = $('Find Next Source Row').first().json.keywords;
return [{ json: { extractedText: text, sourceUrl, topic, keywords } }];

