const pplxResponse = $input.first().json;
let blogHtml = pplxResponse.choices[0].message.content;

// Strip any markdown code fences if AI wrapped output
blogHtml = blogHtml.replace(/^```html\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

// Extract title from h1
const titleMatch = blogHtml.match(/<h1[^>]*>(.*?)<\/h1>/i);
const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim() : $('Find Next Source Row').first().json.topic;

// SEO handle
const handle = title.toLowerCase().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/^-+|-+$/g, '').substring(0, 60);

// Meta description (first 160 chars of text)
const stripped = blogHtml.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
const metaDescription = stripped.substring(0, 160);

const keywords = $('Find Next Source Row').first().json.keywords;
const sourceUrl = $('Find Next Source Row').first().json.sourceUrl;
const rowIndex = $('Find Next Source Row').first().json.rowIndex;

// Social caption (clean, no emojis per brand guidelines)
const caption = `New on the Wax & Wane blog: "${title}"\n\nWe researched the science so you don't have to. Read the full article at waxandwane.store/blogs/wax-wane-blog/${handle}\n\n#WaxAndWane #WellnessResearch #CleanBeauty #SkinScience #HolisticBeauty`;

return [{ json: { title, handle, body_html: blogHtml, metaDescription, keywords, sourceUrl, rowIndex, caption } }];

